#!/usr/bin/env node

/**
 * Generate device-framed showcase images from raw E2E screenshots.
 *
 * Wraps each screenshot in a macOS-style window frame (title bar with
 * traffic-light buttons, rounded corners, subtle shadow) to produce
 * marketing-quality images for the README gallery.
 *
 * Usage:
 *   pnpm e2e:showcase
 *
 * Prerequisites:
 *   - Raw screenshots must exist in docs/e2e/screenshots/
 *     (generated by pnpm e2e:screenshots:local or pnpm e2e:screenshots:docker)
 *   - Playwright browsers installed (npx playwright install chromium)
 *
 * Output:
 *   docs/readme/showcase/*.png
 */

import { execSync } from 'node:child_process'

console.log('Generating device-framed showcase images...\n')

try {
  execSync(
    'npx playwright test -c playwright.showcase.config.ts',
    {
      stdio: 'inherit',
      cwd: new URL('../../apps/desktop', import.meta.url).pathname,
    },
  )
  console.log('\nShowcase images saved to docs/readme/showcase/')
} catch (error) {
  console.error('\nShowcase generation failed. Make sure raw screenshots exist in docs/e2e/screenshots/')
  process.exit(1)
}
